import AsyncStorage from '@react-native-async-storage/async-storage';

class LocalDataManager {
  static async storeData(key, value) {
    try {
      await AsyncStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
      console.error('Failed to save data', e);
    }
  }

  static async getData(key) {
    try {
      const jsonValue = await AsyncStorage.getItem(key);
      return jsonValue != null ? JSON.parse(jsonValue) : null;
    } catch(e) {
      console.error('Failed to fetch data', e);
    }
  }

  static async removeData(key) {
    try {
      await AsyncStorage.removeItem(key);
    } catch(e) {
      console.error('Failed to remove data', e);
    }
  }

  static async clearAll() {
    try {
      await AsyncStorage.clear();
    } catch(e) {
      console.error('Failed to clear all data', e);
    }
  }

  // Example usage
  static async storeUserToken(token) {
    await this.storeData('userToken', token);
  }

  static async getUserToken() {
    return await this.getData('userToken');
  }

  static async removeUserToken() {
    await this.removeData('userToken');
  }

  static async storeUserProfile(profile) {
    await this.storeData('userProfile', profile);
  }

  static async getUserProfile() {
    return await this.getData('userProfile');
  }

  static async removeUserProfile() {
    await this.removeData('userProfile');
  }

  static async storeAppSettings(settings) {
    await this.storeData('appSettings', settings);
  }

  static async getAppSettings() {
    return await this.getData('appSettings');
  }

  static async removeAppSettings() {
    await this.removeData('appSettings');
  }
}

export default LocalDataManager;